import React from 'react';

const Hero = ({ movie }) => {
  if (!movie) return null;

  return (
    <section className="relative h-[870px] w-full overflow-hidden">
      <div className="absolute inset-0 z-0">
        <img 
          alt={movie.title} 
          className="w-full h-full object-cover scale-105" 
          src={movie.backdrop || "https://lh3.googleusercontent.com/aida-public/AB6AXuBSLP-XvZR_HeKfyWsnI7lc9V5DNgCD5080xr6C-g9Q6PVu7Dx1BIiHKE2ziOQOWioLbeJQ0wxDdNvty75z-UMUEBhZTZo6CEUvrcA6qcvSeqp8zAQO_GgkoVCfv1aAbZyN6NqqTzzxWzOBL0EWnlMIY0KhW354G6UgNtJCUv-jm4h1hQ9J7wFvIiiywwop32AQj0YOf86P2ThNJ7H65RHIKxAqm7s-Wospw2EyEt40yWLVh--m2WzBMJb0nKp130pbuYFYMUtIxeLE"}
        />
        <div className="absolute inset-0 hero-gradient"></div>
        <div className="absolute inset-0 bg-gradient-to-r from-surface via-surface/40 to-transparent"></div>
      </div>
      <div className="relative z-10 h-full flex flex-col justify-end px-8 md:px-16 pb-20 max-w-4xl">
        <div className="flex items-center gap-3 mb-4">
          <span className="bg-secondary-container text-on-secondary-container px-3 py-1 rounded-full text-xs font-bold tracking-widest uppercase flex items-center gap-1.5">
            <span className="material-symbols-outlined text-sm" style={{ fontVariationSettings: "'FILL' 1" }}>auto_awesome</span>
            {Math.round(movie.similarity * 100 || 98)}% Match
          </span>
          <span className="text-on-surface-variant font-label text-xs tracking-widest uppercase">
            {movie.genres?.join(' • ') || 'Sci-Fi Thriller'} • {movie.year || '2024'}
          </span>
        </div>
        <h1 className="font-headline text-5xl md:text-7xl font-extrabold tracking-tighter mb-6 leading-[0.9] text-on-surface uppercase">
          {movie.title}
        </h1>
        <p className="text-on-surface/80 text-lg md:text-xl font-body mb-8 max-w-2xl leading-relaxed">
          {movie.synopsis || movie.overview || "In a world where memories are currency, a data-thief uncovers a conspiracy buried deep within the city's central mainframe."}
        </p>
        <div className="flex flex-wrap gap-4">
          <button className="bg-gradient-to-br from-primary-container to-primary text-on-primary font-bold px-8 py-3.5 rounded-lg flex items-center gap-2 hover:opacity-90 transition-all scale-100 active:scale-95 shadow-xl shadow-primary-container/20">
            <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>play_arrow</span>
            Watch Now
          </button>
          <button className="bg-surface-container-high text-on-surface font-bold px-8 py-3.5 rounded-lg flex items-center gap-2 hover:bg-surface-bright transition-all scale-100 active:scale-95">
            <span className="material-symbols-outlined">info</span>
            Why it's for you
          </button>
        </div>
      </div>
    </section>
  );
};

export default Hero;
